<script lang="ts">  import { page } from '$app/stores'  import { goto } from '$app/navigation'  import { createSupabaseBrowserClient } from '$lib/supabase'  import type { Snippet } from 'svelte'  let { children }: { children: Snippet } = $props()  const supabase = createSupabaseBrowserClient()  let instanceId = $derived($page.params.id ?? null)  const primaryNav = [    { label: 'Instances', href: '/app/instances' },    { label: 'Activity',  href: '/app/activity' },    { label: 'Team',      href: '/app/team' },    { label: 'Billing',   href: '/app/billing' },  ]  const instanceNav = [    { label: 'Dashboard',     suffix: '' },    { label: 'Configuration', suffix: '/config' },    { label: 'Memory',        suffix: '/memory' },    { label: 'Audit log',     suffix: '/audit' },    { label: 'Artifacts',     suffix: '/artifacts' },    { label: 'API keys',      suffix: '/keys' },    { label: 'Invocations',         suffix: '/usage' },    { label: 'Settings',      suffix: '/settings' },  ]  function navHref(suffix: string) {    return `/app/instances/${instanceId}${suffix}`  }  function isPrimaryActive(href: string) {    return $page.url.pathname.startsWith(href)  }  function isInstanceActive(suffix: string) {    if (!instanceId) return false    const href = navHref(suffix)    if (suffix === '') return $page.url.pathname === href    return $page.url.pathname.startsWith(href)  }  async function signOut() {    await supabase.auth.signOut()    goto('/login')  }</script><div class="flex min-h-screen">  <!-- Sidebar -->  <aside class="w-60 bg-ink flex flex-col flex-shrink-0 fixed top-0 left-0 h-full z-20">    <!-- Mark -->    <div class="px-6 pt-6 pb-5" style="border-bottom: 1px solid rgba(255,255,255,0.08)">      <a href="/app/instances" class="flex items-center gap-3">        <svg width="28" height="22" viewBox="0 0 100 80" xmlns="http://www.w3.org/2000/svg">          <path d="M 10 40 C 10 18 40 6 50 6 C 60 6 90 18 90 40"            fill="none" stroke="white" stroke-width="2.5" stroke-linecap="round"/>          <path d="M 10 40 C 10 62 40 74 50 74 C 60 74 90 62 90 40"            fill="none" stroke="white" stroke-width="2.5" stroke-linecap="round"/>          <circle cx="50" cy="40" r="8" fill="white"/>          <circle cx="50" cy="40" r="4.5" fill="#1A3AFF"/>        </svg>        <span class="font-syne font-bold text-xs tracking-widest uppercase" style="color: rgba(255,255,255,0.5)">Thalium</span>      </a>    </div>    <!-- Primary nav -->    <nav class="px-3 pt-4">      {#each primaryNav as item}        <a          href={item.href}          class="flex items-center px-3 py-2.5 rounded font-syne font-bold text-sm mb-0.5 transition-colors duration-150"          style={isPrimaryActive(item.href)            ? 'color: white; background: rgba(255,255,255,0.08); border-left: 2px solid #1A3AFF; margin-left: -1px; padding-left: 11px;'            : 'color: rgba(255,255,255,0.5);'}        >          {item.label}        </a>      {/each}    </nav>    <!-- Instance sub-nav -->    {#if instanceId}      <div class="px-3 mt-4 pt-4" style="border-top: 1px solid rgba(255,255,255,0.08)">        <p class="px-3 font-mono text-xs uppercase tracking-wider mb-2" style="color: rgba(255,255,255,0.3)">Instance</p>        {#each instanceNav as item}          <a            href={navHref(item.suffix)}            class="flex items-center px-3 py-2 rounded font-syne text-sm mb-0.5 transition-colors duration-150"            style={isInstanceActive(item.suffix)              ? 'color: white; background: rgba(255,255,255,0.08); border-left: 2px solid #1A3AFF; margin-left: -1px; padding-left: 11px; font-weight: 700;'              : 'color: rgba(255,255,255,0.4);'}          >            {item.label}          </a>        {/each}      </div>    {/if}    <div class="flex-1"></div>    <!-- User -->    <div class="px-6 py-5" style="border-top: 1px solid rgba(255,255,255,0.08)">      <div class="flex items-center justify-between">        <div class="min-w-0">          <p class="font-syne font-bold text-xs truncate" style="color: rgba(255,255,255,0.7)">            {$page.data.user?.email ?? ''}          </p>          <p class="font-mono text-xs mt-0.5" style="color: rgba(255,255,255,0.3)">Owner</p>        </div>        <button          onclick={signOut}          class="font-mono text-xs ml-3 flex-shrink-0 transition-colors"          style="color: rgba(255,255,255,0.3)"        >out</button>      </div>    </div>  </aside>  <!-- Main -->  <div class="flex-1 ml-60 flex flex-col min-h-screen">    <!-- Top bar -->    <header class="h-14 bg-white border-b border-rule flex items-center px-10 flex-shrink-0 sticky top-0 z-10">      <span class="font-syne text-sm" style="color: rgba(13,13,13,0.4)">Thalium</span>    </header>    <!-- Content -->    <main class="flex-1 bg-paper px-10 py-10">      <div class="max-w-content mx-auto">        {@render children()}      </div>    </main>  </div></div>